import { test } from 'node:test'
import assert from 'node:assert/strict'
import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
} from './geo'

// Helper to build a Headers object from a plain record
function makeHeaders(entries: Record<string, string>): Headers {
  const h = new Headers()
  for (const [k, v] of Object.entries(entries)) {
    h.set(k, v)
  }
  return h
}

test('geo() extracts all Vercel headers', () => {
  const headers = makeHeaders({
    'x-vercel-ip-city': 'New York',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'NY',
    'x-vercel-ip-latitude': '40.7128',
    'x-vercel-ip-longitude': '-74.0060',
    'x-vercel-ip-timezone': 'America/New_York',
  })
  const result = geo({ headers })
  assert.equal(result.city, 'New York')
  assert.equal(result.countryCode, 'US')
  assert.equal(result.country, 'United States')
  assert.equal(result.region, 'NY')
  assert.equal(result.latitude, '40.7128')
  assert.equal(result.longitude, '-74.0060')
  assert.equal(result.timezone, 'America/New_York')
})

test('geoFromHeaders() resolves country name from countryCode', () => {
  const headers = makeHeaders({ 'x-vercel-ip-country': 'JP' })
  const result = geoFromHeaders(headers)
  assert.equal(result.countryCode, 'JP')
  assert.equal(result.country, 'Japan')
})

test('geoFromHeaders() falls back to cf-ipcountry when x-vercel-ip-country is absent', () => {
  const headers = makeHeaders({ 'cf-ipcountry': 'DE' })
  const result = geoFromHeaders(headers)
  assert.equal(result.countryCode, 'DE')
  assert.equal(result.country, 'Germany')
})

test('x-vercel-ip-country takes priority over cf-ipcountry', () => {
  const headers = makeHeaders({
    'x-vercel-ip-country': 'GB',
    'cf-ipcountry': 'FR',
  })
  const result = geoFromHeaders(headers)
  assert.equal(result.countryCode, 'GB')
  assert.equal(result.country, 'United Kingdom')
})

test('missing headers return undefined fields without crashing', () => {
  const result = geoFromHeaders(new Headers())
  assert.equal(result.city, undefined)
  assert.equal(result.country, undefined)
  assert.equal(result.countryCode, undefined)
  assert.equal(result.region, undefined)
  assert.equal(result.latitude, undefined)
  assert.equal(result.longitude, undefined)
  assert.equal(result.timezone, undefined)
})

test('isInRegion() returns true when countryCode matches', () => {
  const result = isInRegion({ countryCode: 'US' }, ['US', 'CA', 'GB'])
  assert.equal(result, true)
})

test('isInRegion() returns false when countryCode does not match', () => {
  const result = isInRegion({ countryCode: 'AU' }, ['US', 'CA', 'GB'])
  assert.equal(result, false)
})

test('isInRegion() comparison is case-insensitive', () => {
  const result = isInRegion({ countryCode: 'us' }, ['US'])
  assert.equal(result, true)
})

test('isInRegion() returns false when countryCode is undefined', () => {
  const result = isInRegion({}, ['US'])
  assert.equal(result, false)
})

test('geoDistance() New York to London is approximately 5570 km', () => {
  // New York: 40.7128° N, 74.0060° W
  // London:   51.5074° N,  0.1278° W
  const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(dist - 5570) < 50,
    `Expected ~5570 km, got ${dist.toFixed(1)} km`
  )
})

test('geoDistance() returns 0 for identical points', () => {
  const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
  assert.equal(dist, 0)
})

